  "Explain why you want to delete this route...": { fr: "Expliquez pourquoi vous voulez supprimer cet itinéraire...", pt: "Explique por que deseja excluir esta rota...", ar: "اشرح سبب رغبتك في حذف هذا المسار...", sw: "Eleza kwa nini unataka kufuta njia hii...", ha: "Bayyana dalilin da ya sa kake son goge wannan hanya...", es: "Explica por qué quieres eliminar esta ruta..." },
  "Explain why you want to delete this vehicle...": { fr: "Expliquez pourquoi vous voulez supprimer ce véhicule...", pt: "Explique por que deseja excluir este veículo...", ar: "اشرح سبب رغبتك في حذف هذه المركبة...", sw: "Eleza kwa nini unataka kufuta gari hili...", ha: "Bayyana dalilin da ya sa kake son goge wannan abin hawa...", es: "Explica por qué quieres eliminar este vehículo..." },
