  "Nothing yet. Send your first one above.": { fr: "Rien pour le moment. Envoyez votre premier retour ci-dessus.", pt: "Nada ainda. Envie o primeiro acima.", ar: "لا شيء بعد. أرسل أول ملاحظة أعلاه.", sw: "Bado hakuna. Tuma ya kwanza hapo juu.", ha: "Babu komai tukuna. Aika na farko a sama.", es: "Nada todavía. Envía el primero arriba." },
  "Notifications clear automatically after 5 min": { fr: "Les notifications disparaissent automatiquement après 5 min", pt: "As notificações somem automaticamente após 5 min", ar: "تُمسح الإشعارات تلقائيًا بعد 5 دقائق", sw: "Arifa hufutika kiotomatiki baada ya dakika 5", ha: "Sanarwa na ɓacewa kai tsaye bayan mintuna 5", es: "Las notificaciones se limpian automáticamente tras 5 min" },
