  "Password updated successfully": { fr: "Mot de passe mis à jour avec succès", pt: "Senha atualizada com sucesso", ar: "تم تحديث كلمة المرور بنجاح", sw: "Nenosiri limesasishwa kikamilifu", ha: "An sabunta kalmar sirri cikin nasara", es: "Contraseña actualizada correctamente" },
  "Past dates are unavailable. Pick a future date.": { fr: "Les dates passées ne sont pas disponibles. Choisissez une date future.", pt: "Datas passadas não estão disponíveis. Escolha uma data futura.", ar: "التواريخ الماضية غير متاحة. اختر تاريخًا مستقبليًا.", sw: "Tarehe zilizopita hazipatikani. Chagua tarehe ya baadaye.", ha: "Kwanakin baya ba su samuwa. Zaɓi kwanan gaba.", es: "Las fechas pasadas no están disponibles. Elige una fecha futura." },
  "Past dates are unavailable. Pick today or a future date.": { fr: "Les dates passées ne sont pas disponibles. Choisissez aujourd'hui ou une date future.", pt: "Datas passadas não estão disponíveis. Escolha hoje ou uma data futura.", ar: "التواريخ الماضية غير متاحة. اختر اليوم أو تاريخًا مستقبليًا.", sw: "Tarehe zilizopita hazipatikani. Chagua leo au tarehe ya baadaye.", ha: "Kwanakin baya ba su samuwa. Zaɓi yau ko kwanan gaba.", es: "Las fechas pasadas no están disponibles. Elige hoy o una fecha futura." },
