  "Public — visible alongside your first name on the homepage.": { fr: "Public — visible avec votre prénom sur la page d'accueil.", pt: "Público — visível junto ao seu primeiro nome na página inicial.", ar: "عام — يظهر بجانب اسمك الأول في الصفحة الرئيسية.", sw: "Ya umma — inaonekana pamoja na jina lako la kwanza kwenye ukurasa wa mwanzo.", ha: "Na jama'a — zai bayyana tare da sunanka na farko a shafin gida.", es: "Público — visible junto a tu nombre en la página principal." },
  "Push notifications": { fr: "Notifications push", pt: "Notificações push", ar: "إشعارات فورية", sw: "Arifa za papo hapo", ha: "Sanarwar turawa", es: "Notificaciones push" },
